// Find star rating buttons by multiple criteriavar starButtons = [];var allButtons = document.querySelectorAll('button, [role="button"], .star, .rating-star');// Look for buttons with star-related attributes or classesfor(var i = 0; i < allButtons.length; i++) {var btn = allButtons[i];var hasStarClass = btn.className && (btn.className.includes('star') || btn.className.includes('rating') || btn.className.includes('cursor-pointer'));var hasStarAttr = btn.getAttribute('data-star') || btn.getAttribute('data-rating');var hasStarText = btn.textContent && (btn.textContent.includes('★') || btn.textContent.includes('star'));if(hasStarClass || hasStarAttr || hasStarText) {starButtons.push(btn);}}// Click the 2nd star if availableif(starButtons.length >= 2) {console.log('Found', starButtons.length, 'star buttons, clicking 2nd');starButtons[1].click();starButtons[1].dispatchEvent(new Event('click', { bubbles: true }));} else {console.log('Only found', starButtons.length, 'star buttons');}
Without any arguments.

